import com.varabyte.kobweb.core.AppGlobals
import com.varabyte.kobweb.navigation.BasePath
import com.varabyte.kobweb.navigation.Router
import com.varabyte.kobweb.navigation.UpdateHistoryMode
import com.varabyte.kobweb.navigation.remove
import com.varabyte.kobweb.silk.defer.DeferringHost
import kotlinx.browser.document
import kotlinx.browser.window
import org.jetbrains.compose.web.renderComposable
import com.example.easypeasyenglish.pages.HomePage as _com_example_easypeasyenglish_pages_HomePage
import com.example.easypeasyenglish.pages.admin.CreatePage as _com_example_easypeasyenglish_pages_admin_CreatePage
import com.example.easypeasyenglish.pages.admin.HomePage as _com_example_easypeasyenglish_pages_admin_HomePage
import com.example.easypeasyenglish.pages.admin.LoginScreen as _com_example_easypeasyenglish_pages_admin_LoginScreen
import com.example.easypeasyenglish.pages.admin.MyPostsPage as _com_example_easypeasyenglish_pages_admin_MyPostsPage
import com.example.easypeasyenglish.pages.admin.Success as _com_example_easypeasyenglish_pages_admin_Success
import com.example.easypeasyenglish.pages.posts.PostPage as _com_example_easypeasyenglish_pages_posts_PostPage
import com.example.easypeasyenglish.pages.search.SearchPage as _com_example_easypeasyenglish_pages_search_SearchPage

public fun main() {
    AppGlobals.initialize(mapOf("title" to "EasyPeayEnglish"))
    BasePath.set("")
    val router = Router()
    com.varabyte.kobweb.core.init.initKobweb(router) { ctx ->
        ctx.router.register(
            "/",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_HomePage()
        }
        ctx.router.register(
            "/admin/",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_admin_HomePage()
        }
        ctx.router.register(
            "/admin/createpost",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_admin_CreatePage()
        }
        ctx.router.register(
            "/admin/login",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_admin_LoginScreen()
        }
        ctx.router.register(
            "/admin/myposts",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_admin_MyPostsPage()
        }
        ctx.router.register(
            "/admin/success",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_admin_Success()
        }
        ctx.router.register(
            "/posts/post",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_posts_PostPage()
        }
        ctx.router.register(
            "/search/query",
        ) { pageCtx -> 
            _com_example_easypeasyenglish_pages_search_SearchPage()
        }

    }
    router.addRouteInterceptor {
        path = path.removeSuffix(".html").removeSuffix(".htm")
    }

    com.varabyte.kobweb.silk.init.additionalSilkInitialization = { ctx ->
        com.varabyte.kobweb.silk.init.initSilkWidgets(ctx)
        com.varabyte.kobweb.silk.init.initSilkWidgetsKobweb(ctx)
        ctx.theme.registerStyle("editor-key", com.example.easypeasyenglish.styles.EditorKeyStyle)
        ctx.theme.registerStyle("category-item", CategoryItemStyle)
        ctx.theme.registerStyle("login-input", com.example.easypeasyenglish.styles.LoginInputStyle)
        ctx.theme.registerStyle("newsletter", com.example.easypeasyenglish.styles.NewsletterStyle)
        ctx.theme.registerStyle("post-preview", com.example.easypeasyenglish.styles.PostPreviewStyle)
        com.example.easypeasyenglish.initStyles(ctx)
    }

    // Dedup any leading slashes after removing the origin, just in case someone typed
    // something like `https://site.com//about` by accident. If we pass `//about` into
    // `tryRoutingTo`, Kobweb will reject it as a protocol-relative URL; instead, we
    // want it to navigate to `/about`
    router.tryRoutingTo(BasePath.remove("/" + window.location.href.removePrefix(window.origin).trimStart('/')), UpdateHistoryMode.REPLACE)

    // For SEO, we may bake the contents of a page in at build time. However, we will
    // overwrite them the first time we render this page with their composable, dynamic
    // versions. Think of this as poor man's hydration :)
    // See also: https://en.wikipedia.org/wiki/Hydration_(web_development)
    val root = document.getElementById("_kobweb-root")!!
    while (root.firstChild != null) { root.removeChild(root.firstChild!!) }

    renderComposable(rootElementId = "_kobweb-root") {
        com.example.easypeasyenglish.AppEntry {
            router.renderActivePage { DeferringHost { it() } }
        }
    }
}
